import { HTMLAttributes, useEffect, useState } from 'preact/compat';
import { Container } from '@adobe-commerce/elsie/lib';
import { Header } from '@/pdp/components';
import { events } from '@adobe-commerce/event-bus';
import { ProductModel } from '@/pdp/data/models';
import { getFetchedProductData } from '@/pdp/api';

export interface ProductHeaderProps extends HTMLAttributes<HTMLDivElement> {
  scope?: string;
  hideSku?: boolean;
  /** When true, show variant SKU when all options are selected (configurable product). Default false. */
  showVariantSku?: boolean;
  /** When true, show variant name when all options are selected (configurable product). Default false. */
  showVariantName?: boolean;
}

export const ProductHeader: Container<
  ProductHeaderProps,
  ProductModel | null
> = ({
  initialData = null,
  scope,
  hideSku = false,
  showVariantSku = false,
  showVariantName = false,
  children,
  ...props
}) => {
  const [data, setData] = useState<ProductModel | null>(initialData);

  useEffect(() => {
    const dataEvent = events.on('pdp/data', setData, { scope });

    return () => {
      dataEvent?.off();
    };
  }, [scope]);

  if (!data) return null;

  return (
    <Header
      {...props}
      title={<>{data.name}</>}
      sku={<>{data.sku}</>}
      hideSku={hideSku}
      variantName={
        showVariantName && data.variantName ? (
          <>{data.variantName}</>
        ) : undefined
      }
      variantSku={
        showVariantSku && data.variantSku ? <>{data.variantSku}</> : undefined
      }
    />
  );
};

ProductHeader.getInitialData = getFetchedProductData;
